+
+  const legacyProject = getProjectIdFromSelectionKey(sessionId);
+  const legacySessionId = getSessionIdFromSelectionKey(sessionId);
+  if (legacyProject && legacySessionId) {
+    return {
+      legacySelectionKey: true,
